      "vendorSLA": "",
      "authenticationModel": "",
      "incidentNotificationProcess": "",
      "owner": {
        "team": "cloud-architecture",
        "contact": "cloud-architecture@example.com"
      },
      "definitionOwner": {},
      "provider": {},
